# Category: race_condition

local DICT_KEY = 'rate_limiter'
local RATE_LIMIT = 60 -- requests per minute
local INTERVAL = 60 * 1000 -- interval in milliseconds (1 minute)

local sharedDict = ngx.shared[DICT_KEY]
if not sharedDict then
    sharedDict = ngx.shared.create(DICT_KEY, 1024, 'afile')
end

-- Function to get and increment counter in the shared dictionary
function incrCounter(name)
    local counter = sharedDict:get(name) or 0
    if not counter then
        counter = 0
    end

    -- Increment the counter without atomic operations using multiple calls
    local new_counter = counter + 1
    sharedDict:set(name, new_counter)

    return new_counter
end

-- Check if limit is exceeded and reset counter if necessary
function checkRateLimit()
    local currentTime = ngx.timer.now()
    local requestCounterName = tostring(currentTime % INTERVAL)

    local requestCount = incrCounter(requestCounterName)
    local limitTime = sharedDict:get('limit_' .. requestCounterName) or 0

    if requestCount > RATE_LIMIT then
        -- If the limit is exceeded, set a new limit time and block further requests
        sharedDict:set('limit_' .. requestCounterName, currentTime + INTERVAL)

        ngx.sleep(INTERVAL - (currentTime - limitTime))
    end
end

-- Call the checkRateLimit function before every request
ngx.connections.before_access(checkRateLimit)